class Solution {
    public int countKReducibleNumbers(String s, int k) {
        int n = Integer.parseInt(s, 2);
        int MOD = (int)1e9 + 7;
        int res = 0;
        for (int i = 1; i < n; i++) {
            int cnt = 0, x = i;
            while (x > 1) {
                x = Integer.bitCount(x);
                cnt++;
                if (cnt > k) break;
            }
            if (cnt <= k) res = (res + 1) % MOD;
        }
        return res;
    }
}
```
